  // GroupConversation
  //

  bool access::view_traits_impl< ::GroupConversation, id_mysql >::
  grow (image_type& i,
        my_bool* t)
  {
    ODB_POTENTIALLY_UNUSED (i);
    ODB_POTENTIALLY_UNUSED (t);

    bool grew (false);

    // conversation_id
    //
    t[0UL] = 0;

    // name
    //
    if (t[1UL])
    {
      i.name_value.capacity (i.name_size);
      grew = true;
    }

    // avatar
    //
    if (t[2UL])
    {
      i.avatar_value.capacity (i.avatar_size);
      grew = true;
    }

    // members
    //
    t[3UL] = 0;

    return grew;
  }

  void access::view_traits_impl< ::GroupConversation, id_mysql >::
  bind (MYSQL_BIND* b,
        image_type& i)
  {
    using namespace mysql;

    mysql::statement_kind sk (statement_select);
    ODB_POTENTIALLY_UNUSED (sk);

    std::size_t n (0);

    // conversation_id
    //
    b[n].buffer_type = MYSQL_TYPE_LONGLONG;
    b[n].is_unsigned = 1;
    b[n].buffer = &i.conversation_id_value;
    b[n].is_null = &i.conversation_id_null;
    n++;

    // name
    //
    b[n].buffer_type = MYSQL_TYPE_STRING;
    b[n].buffer = i.name_value.data ();
    b[n].buffer_length = static_cast<unsigned long> (
      i.name_value.capacity ());
    b[n].length = &i.name_size;
    b[n].is_null = &i.name_null;
    n++;

    // avatar
    //
    b[n].buffer_type = MYSQL_TYPE_STRING;
    b[n].buffer = i.avatar_value.data ();
    b[n].buffer_length = static_cast<unsigned long> (
      i.avatar_value.capacity ());
    b[n].length = &i.avatar_size;
    b[n].is_null = &i.avatar_null;
    n++;

    // members
    //
    b[n].buffer_type = MYSQL_TYPE_LONGLONG;
    b[n].is_unsigned = 1;
    b[n].buffer = &i.members_value;
    b[n].is_null = &i.members_null;
    n++;
  }

  void access::view_traits_impl< ::GroupConversation, id_mysql >::
  init (view_type& o,
        const image_type& i,
        database* db)
  {
    ODB_POTENTIALLY_UNUSED (o);
    ODB_POTENTIALLY_UNUSED (i);
    ODB_POTENTIALLY_UNUSED (db);

    // conversation_id
    //
    {
      ::size_t& v =
        o.conversation_id;

      mysql::value_traits<
          ::size_t,
          mysql::id_ulonglong >::set_value (
        v,
        i.conversation_id_value,
        i.conversation_id_null);
    }

    // name
    //
    {
      ::std::string& v =
        o.name;

      mysql::value_traits<
          ::std::string,
          mysql::id_string >::set_value (
        v,
        i.name_value,
        i.name_size,
        i.name_null);
    }

    // avatar
    //
    {
      ::std::string& v =
        o.avatar;

      mysql::value_traits<
          ::std::string,
          mysql::id_string >::set_value (
        v,
        i.avatar_value,
        i.avatar_size,
        i.avatar_null);
    }

    // members
    //
    {
      ::size_t& v =
        o.members;

      mysql::value_traits<
          ::size_t,
          mysql::id_ulonglong >::set_value (
        v,
        i.members_value,
        i.members_null);
    }
  }

